import hashlib

def sign_message(hash_name, message):
    hash_obj = hashlib.new(hash_name)
    hash_obj.update(message)
    return hash_obj.digest()

turn2_code:
import hashlib

def sign_message(hash_name, message):
    try:
        hash_obj = hashlib.new(hash_name)
        hash_obj.update(message)
        return hash_obj.digest()
    except ValueError:
        raise ValueError(f"Unsupported hash algorithm: {hash_name}")

turn3_code:
import hashlib
import hmac

def sign_message(hash_name, message, key):
    try:
        return hmac.new(key, message, hash_name).digest()
    except ValueError:
        raise ValueError(f"Unsupported hash algorithm: {hash_name}")
